import { HTMLAttributes, ReactNode } from 'react';
import { TestComponentProps } from 'src/types/test-component';
export type HeroBannerImagePosition = 'absolute' | 'relative';
export interface HeroBannerAction {
    label: ReactNode;
    /**
     * Желтая / обычная кнопка
     */
    primary?: boolean;
    disabled?: boolean;
    /**
     * Любые произвольные данные
     */
    meta?: Record<string, unknown>;
    'aria-label'?: string;
    href?: string;
}
export interface HeroBannerProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'>, TestComponentProps {
    /**
     * Заголовок. Можно строку или готовый ReactNode.
     */
    header?: ReactNode;
    /**
     * Подзаголовок/описание.
     */
    headline?: ReactNode;
    /**
     * Картинка. Можно:
     *  - строку
     *  - ReactNode (например, <img /> или любая разметка)
     */
    image?: string | ReactNode;
    imageAlt?: string;
    /**
     * Позиция картинки
     * @param absolute - абсолютное позиционирование
     * @param relative - картинка блочный элемент
     */
    imagePosition?: HeroBannerImagePosition;
    /**
     * Список действий (кнопок).
     */
    actions?: HeroBannerAction[];
    /**
        Кастомный рендер кнопки
     */
    renderAction?: (action: HeroBannerAction, onClick: () => void) => ReactNode;
    /**
     * Колбэк клика по действию.
     */
    onAction?: (action: HeroBannerAction) => void;
}
